window.maskMobileNumber = (mobileNumber) => {
  // Ensure the input is a string and has exactly 10 digits
  if (typeof mobileNumber !== 'string' || mobileNumber.length !== 10) {
    return mobileNumber;
  }

  // Mask the first 6 digits with 'X' and keep the last 4 digits
  const maskedNumber = 'XXXXXX' + mobileNumber.slice(-4);
  return maskedNumber;
}
